/**
 * Props for `ChartTooltip.ActionsPlaceholder`, shown in the tooltip footer before it is pinned.
 * @public
 */
export interface ActionsPlaceholderProps {
  /** Placeholder text shown when tooltip is not pinned */
  text: string;
}

/**
 * Placeholder shown in the tooltip footer when not pinned.
 * When the tooltip becomes pinned, this is replaced by the Action components.
 * @public
 */
export const ActionsPlaceholder = (_props: ActionsPlaceholderProps) => {
  return null;
};
